  ('heringsoel', 'fischoel-allgemein', 'positiv', 'mittel', 'A→B', 'Heringsöl-Cetolsäure (11-15%) fördert EPA/DHA-Speicherung in anderen Ölen', 'Lachse mit Heringsöl-Fütterung: +10% EPA+DHA-Speicherung', 'Heringsöl kann EPA/DHA-Verwertung aus anderen Quellen verbessern', '-', 'Mittel', 'Nofima Research; Ruyter'),
  ('l-theanin', 'koffein', 'positiv', 'stark', 'bidirektional', '✅✅ BESTUNTERSUCHTE SYNERGIE! Koffein erhöht Dopamin/Noradrenalin (Wachheit), L-Theanin erhöht GABA/moduliert Glutamat (Entspannung) → "Relaxed Alertness" ohne Jitteriness.', '✅✅ Meta-Analysen: Moderate Effektstärken für Alertness und Attention-Switching. L-Theanin eliminiert vasokonstriktiven Effekt von Koffein.', '✅✅ EMPFOHLEN! Optimales Verhältnis 2:1 (L-Theanin:Koffein), z.B. 100-200mg + 50-100mg Koffein.', '0', 'Hoch', 'PMID 18681988; 18006208; 22326943; 26869148'),
  ('l-theanin', 'gaba', 'positiv', 'mittel', 'bidirektional', '✅ Synergistisch für Entspannung/Schlaf. L-Theanin erhöht GABA indirekt; GABA wirkt direkt.', '✅ PMC6366437: Kombination verbesserte Schlaflatenz und -dauer stärker als Einzelsubstanzen.', '✅ Sinnvolle Kombination für Schlaf und Entspannung.', '0', 'Mittel', 'PMC6366437'),
  ('l-theanin', 'magnesium', 'positiv', 'mittel', 'bidirektional', '✅ Additiv für GABA-Effekte. Beide modulieren Glutamat/GABA-Balance.', '✅ PMC9017334: Kombination zeigt verstärkte entspannende Wirkung.', '✅ Können kombiniert werden.', '0', 'Mittel', 'PMC9017334'),
  ('l-theanin', 'melatonin', 'positiv', 'schwach', 'bidirektional', '✅ Kompatibel für Schlaf. L-Theanin (Entspannung) + Melatonin (Schlaf-Timing).', '⚠️ Anekdotische Evidenz; keine direkte RCT zur Kombination.', '✅ Können kombiniert werden für Schlafoptimierung.', '0', 'Niedrig', 'Anekdotisch'),
  ('l-theanin', '5-htp', 'neutral', 'schwach', 'bidirektional', '⚠️ Beide haben serotonerge Effekte. L-Theanin moduliert Serotonin indirekt.', '⚠️ Keine dokumentierten Interaktionsfälle, aber theoretisches Risiko bei Kombination mit SSRIs.', '⚠️ Mit Vorsicht; bei serotoninergen Medikamenten: ärztliche Rücksprache erforderlich.', '0', 'Niedrig', 'Theoretisch'),
  ('l-theanin', 'ashwagandha', 'positiv', 'schwach', 'bidirektional', '✅ Beide anxiolytisch/adaptogen. Unterschiedliche Mechanismen (GABAerg vs. HPA-Achse).', '⚠️ Begrenzte direkte Evidenz zur Kombination.', '✅ Theoretisch sinnvoll für Stressmanagement.', '0', 'Niedrig', 'Theoretisch'),
  ('caprinsaeure-c10', 'caprylsaeure-c8', 'positiv', 'stark', 'bidirektional', 'KOMPLEMENTÄRE WIRKUNG: C8 = maximale Ketogenese (3x ketogener). C10 = direkte AMPA-Rezeptor-Hemmung (antikonvulsiv). Kombination deckt beide Mechanismen ab.', 'C8 liefert Ketone, C10 liefert direkte Anfallskontrolle. Optimal für MCT-ketogene Diät.', 'Standard-MCT (60:40 C8:C10) für allgemeine Anwendung. Bei Epilepsie: C10-Anteil erhöhen!', '-', 'Hoch', 'St-Pierre 2019, Chang 2016'),
  ('caprinsaeure-c10', 'perampanel', 'positiv', 'stark', 'bidirektional', '⭐ ECHTE SYNERGIE (nicht nur additiv)! Beide sind AMPA-Antagonisten, aber mit UNTERSCHIEDLICHEN Bindungsstellen: C10 = M3-Helix (Kanal), Perampanel = S1-M1-Linker. Augustin et al. 2018 (Epilepsia).', 'Synergistische Anfallskontrolle. Niedrigere Perampanel-Dosen möglich → weniger Nebenwirkungen.', 'Kombination unter ärztlicher Aufsicht bei therapieresistenter Epilepsie erwägen.', '-', 'Hoch', 'Augustin 2018 (Epilepsia), Chang 2016'),
  ('caprinsaeure-c10', 'capronsaeure-c6', 'neutral', 'mittel', 'C10 >> C6', 'C6 hat KEINE AMPA-Rezeptor-Hemmung und starke GI-Nebenwirkungen. C10 hat AMPA-Hemmung UND beste GI-Verträglichkeit.', 'C10 ist in jeder Hinsicht vorzuziehen.', 'C6 wird aus hochwertigen MCT-Produkten entfernt. C10 ist Bestandteil.', '-', 'Mittel', 'Chang 2016'),
  ('caprinsaeure-c10', 'laurinsaeure-c12', 'neutral', 'mittel', 'C10 > C12', 'C12 (Laurinsäure) hat KEINE AMPA-Rezeptor-Hemmung und ist metabolisch eher wie langkettige Fettsäure (braucht Carnitin). C10 hat direkte neurologische Effekte.', 'Für neurologische Anwendungen ist C10 klar vorzuziehen.', 'MCT-Öle sollten C12-arm sein. C10-Anteil ist wichtiger.', '-', 'Mittel', 'Chang 2016, Neurologie-Reviews'),
  ('makrelenoel', 'vitamin-e', 'positiv', 'stark', 'bidirektional', 'Vitamin E schützt Omega-3 vor Oxidation. Tierstudie (Wiseman 1978): Makrelenöl ohne ausreichend Vit.E führte zu Yellow Fat Disease!', 'Oxidationsschutz kritisch bei hohem PUFA-Gehalt', 'Kombination EMPFOHLEN - Makrelenöl benötigt Vitamin E', '-', 'Hoch', 'Wiseman 1978 PMID 215027'),
  ('makrelenoel', 'fischoel-allgemein', 'neutral', 'schwach', 'bidirektional', 'Makrelenöl ist DHA-dominant (1:1,6-2). Kombination mit EPA-dominanten Ölen (Anchovis) kann Verhältnis optimieren.', 'EPA:DHA-Balance optimierbar', 'Gesamtdosis beachten (max. 5g/Tag)', '-', 'Mittel', 'Theoretische Überlegung'),
  ('thunfischoel', 'vitamin-e', 'positiv', 'mittel', 'bidirektional', 'Vitamin E schützt DHA vor Oxidation', 'Stabilität verbessert', 'Kombination empfohlen', '-', 'Hoch', 'GOED'),
  ('thunfischoel', 'algenoel', 'neutral', 'schwach', 'bidirektional', 'Beide DHA-dominant. Thunfischöl: EPA:DHA 1:4. Algenöl: fast nur DHA.', 'Ähnliches DHA-Profil - Redundanz', 'Für Veganer: Algenöl. Sonst: Thunfischöl (günstiger, RCT-Evidenz)', '-', 'Niedrig', 'Vergleich'),
  ('thunfischoel', 'anchovisoel', 'positiv', 'mittel', 'bidirektional', 'Thunfischöl: DHA-dominant (1:4). Anchovisöl: EPA-dominant (1,5:1). Komplementäre Profile!', 'Optimiertes EPA:DHA-Verhältnis möglich', 'Kombination sinnvoll für balanciertes Omega-3-Profil', '-', 'Mittel', 'Rationale Kombination'),
  ('thunfischoel', 'saeuglings-dha', 'positiv', 'stark', 'A→B', 'Thunfischöl-DHA ähnelt Muttermilch-Profil. Wird in Säuglingsnahrung verwendet.', 'Optimale DHA-Quelle für Säuglingsnahrung', 'Thunfischöl (Skipjack) für DHA-Anreicherung von Säuglingsnahrung geeignet', '-', 'Hoch', 'PMC 7019307; N3RO Trial'),
  ('kreatin-monohydrat', 'hmb', 'positiv', 'mittel', 'bidirektional', '✅ ADDITIV! Verschiedene Mechanismen: Kreatin (ATP/Zellvolumisierung) vs. HMB (Proteinsynthese/Anti-Katabolismus).', '✅ Jówko 2001 (PMID 11448573): FFM +1,54kg (kombiniert) vs. +0,92kg (Kreatin allein) vs. +0,39kg (HMB allein). p=0,73 für Interaktion = additiv.', '✅ Kombination sinnvoll, besonders für Trainingsanfänger und Ältere.', '0', 'Hoch', 'PMID 11448573'),
  ('kreatin-monohydrat', 'beta-alanin', 'positiv', 'mittel', 'bidirektional', '✅ Komplementäre Mechanismen: Kreatin (PCr-System, 5-8 Sek.) + Beta-Alanin (Carnosin-Puffer, 1-4 Min.).', '✅ Sinnvolle Kombination für hochintensives Training verschiedener Dauern.', '✅ Können zusammen eingenommen werden.', '0', 'Mittel', 'ISSN Position Stands'),
  ('kreatin-monohydrat', 'protein', 'positiv', 'schwach', 'bidirektional', '✅ Protein/Kohlenhydrate können muskuläre Kreatin-Aufnahme erhöhen (Insulin-Effekt).', '⚠️ Kein nachgewiesener zusätzlicher LEISTUNGS-Effekt durch Ko-Ingestion.', '✅ Können zusammen eingenommen werden; praktisch für Post-Workout-Shake.', '0', 'Mittel', 'PMID 28615996'),
  ('kreatin-monohydrat', 'koffein', 'neutral', 'schwach', 'bidirektional', '⚠️ KONTROVERS! Vandenberghe 1996: Koffein eliminierte Kreatin-Leistungsvorteile. ABER: Systematic Review 2022: Ergebnisse INKONKLUSIV.', '⚠️ 3 Studien: keine Interferenz; 2 Studien: Interferenz; 3 Studien: kein Unterschied.', '⚠️ Bei Unsicherheit: Einnahme um 4-5 Stunden trennen.', '4', 'Niedrig', 'PMID 8929583; PMID 35016154'),
  ('hmb', 'protein', 'positiv', 'schwach', 'bidirektional', '✅ HMB ist Leucin-Metabolit; Protein liefert Substrate für Muskelproteinsynthese.', '⚠️ Zusätzliche Leucin-Supplementation möglicherweise redundant (HMB = Leucin-Endprodukt).', '✅ Können kombiniert werden; normale Proteinzufuhr ausreichend.', '0', 'Niedrig', 'Physiologie'),
  ('hmb', 'vitamin-d', 'positiv', 'schwach', 'bidirektional', '✅ Beide relevant für Muskelgesundheit bei Älteren; Vitamin D für Muskelproteinsynthese wichtig.', '⚠️ Begrenzte direkte Kombinationsstudien.', '✅ Sinnvolle Kombination für Sarkopenie-Prävention bei Älteren.', '0', 'Niedrig', 'Theoretisch'),
  ('tintenfischoel', 'vitamin-e', 'positiv', 'mittel', 'bidirektional', 'Vitamin E schützt Omega-3 vor Oxidation', 'Verlängerte Stabilität', 'Kombination empfohlen', '-', 'Hoch', 'GOED'),
  ('tintenfischoel', 'krilloel', 'neutral', 'schwach', 'bidirektional', 'Tintenfischöl: ~5% Phospholipide, EPA:DHA ~1:2. Krillöl: ~40% Phospholipide, EPA:DHA ~2:1.', 'Unterschiedliche Bioverfügbarkeit und EPA:DHA-Profile', 'Für DHA-Fokus: Tintenfischöl. Für Phospholipide: Krillöl.', '-', 'Mittel', 'Produktvergleich'),
  ('tintenfischoel', 'thunfischoel', 'neutral', 'schwach', 'bidirektional', 'Beide DHA-dominant. Tintenfischöl: EPA:DHA ~1:2. Thunfischöl: EPA:DHA ~1:4.', 'Ähnliche DHA-Dominanz', 'Thunfischöl noch DHA-reicher. Tintenfischöl: Cadmium beachten.', '-', 'Niedrig', 'Profilvergleich'),
  ('epa', 'statine', 'positiv', 'stark', 'bidirektional', 'EPA + Statin: Synergistische kardiovaskuläre Prävention. JELIS: 19% RRR. REDUCE-IT: 25% RRR (alle auf Statinen).', 'Additive CV-Risikoreduktion', '⭐ EMPFOHLEN: EPA + Statin bei erhöhten Triglyceriden + CV-Risiko', '-', 'Hoch', 'JELIS 2007; REDUCE-IT 2019'),
  ('epa', 'dha', 'neutral', 'mittel', 'bidirektional', 'EPA: Anti-inflammatorisch, erhöht LDL NICHT. DHA: Gehirn/Sehkraft, KANN LDL erhöhen. STRENGTH: EPA+DHA UNWIRKSAM!', 'Unterschiedliche Wirkprofile. Kombination evtl. kontraproduktiv für CV.', '⚠️ Für kardiovaskuläre Prävention: EPA ALLEIN (nicht EPA+DHA!)', '-', 'Hoch', 'REDUCE-IT vs. STRENGTH'),
  ('epa', 'vitamin-e', 'positiv', 'mittel', 'bidirektional', 'Vitamin E schützt EPA vor Oxidation. Hochkonzentrierte EPA-Präparate oxidationsempfindlich.', 'Stabilität verbessert', 'Kombination empfohlen', '-', 'Hoch', 'GOED'),
  ('epa', 'algenoel-epa', 'positiv', 'stark', 'A→B', 'Nannochloropsis-Algenöl: EPA in Polarlipidform, 50% höhere Absorption als Fischöl-EPA.', 'Verbesserte Bioverfügbarkeit', 'Vegane Alternative mit höherer Absorption', '-', 'Mittel', 'PMC10876867; AlmegaPL'),
  ('laurinsaeure-c12', 'caprylsaeure-c8', 'neutral', 'stark', 'C8 >> C12', '⚠️ C8 ist 6x KETOGENER als C12! C12 braucht Carnitin-Shuttle, C8 nicht. C12 in MCT-Öl VERDÜNNT die ketogene Wirkung.', 'Für Ketose: C12 ist kontraproduktiv. Für antimikrobiell: C12 ist stärker.', 'Für Ketose: MCT-Öl OHNE C12 wählen! Kokosöl ist für Ketose NICHT geeignet (45-53% C12).', '-', 'Hoch', 'St-Pierre 2019, Vandenberghe 2019'),
  ('laurinsaeure-c12', 'caprinsaeure-c10', 'neutral', 'mittel', 'C10 > C12', 'C10 ist 2x ketogener als C12 und hat AMPA-Rezeptor-Hemmung. C12 hat KEINE AMPA-Hemmung (bekannt). C12 ist aber antimikrobiell stärker.', 'Für Epilepsie: C10 >> C12. Für antimikrobiell: C12 > C10.', 'Indikationsabhängig wählen.', '-', 'Mittel', 'St-Pierre 2019, Kabara 1972'),
  ('laurinsaeure-c12', 'monolaurin', 'positiv', 'stark', 'C12 → Monolaurin', 'Laurinsäure wird im Körper zu Monolaurin (Glycerylmonolaurat) umgewandelt. Monolaurin ist bis zu 200x POTENTER antimikrobiell als freie Laurinsäure!', 'Für maximale antimikrobielle Wirkung: Monolaurin-Supplements statt Kokosöl.', 'Monolaurin-Kapseln (z.B. Lauricidin) für gezielte antimikrobielle Anwendung.', '-', 'Hoch', 'Kabara 1972, Hierholzer 1982'),
  ('laurinsaeure-c12', 'omega-3-fettsaeuren', 'positiv', 'mittel', 'bidirektional', 'C12 erhöht LDL UND HDL. Omega-3 senkt Triglyceride und kann das Lipidprofil bei hohem C12-Konsum ausgleichen.', 'Bei hohem Kokosölkonsum: Omega-3-Supplementierung erwägen.', 'Kombination kann Lipidprofil-Nachteile von C12 abmildern.', '-', 'Mittel', 'Allgemeine Ernährungsempfehlungen'),
  ('gaba', 'l-theanin', 'positiv', 'stark', 'bidirektional', '✅✅ SYNERGIE! Beide erhöhen Alpha-Wellen und GABA-Aktivität über unterschiedliche Mechanismen.', '✅ Kim et al. 2019 (PMC6366437): Schlaflatenz -20,7%, Schlafdauer +87,3%, Schlafeffizienz +11,8%', '✅✅ EMPFOHLENE KOMBINATION für Schlaf und Entspannung!', '0', 'Hoch', 'PMC6366437'),
  ('gaba', 'magnesium', 'positiv', 'mittel', 'bidirektional', '✅ Komplementäre Mechanismen: GABA (GABA-Rezeptoren) + Mg (NMDA-Antagonist, GABA-Agonist).', '✅ Additive Effekte auf Entspannung und Schlaf theoretisch.', '✅ Sinnvolle Kombination für Entspannung/Schlaf.', '0', 'Mittel', 'Physiologie; PMC9017334'),
  ('gaba', 'melatonin', 'positiv', 'mittel', 'bidirektional', '✅ Unterschiedliche Schlafmechanismen: GABA (Entspannung) + Melatonin (zirkadiane Regulation).', '⚠️ Keine negativen Interaktionen dokumentiert.', '✅ Kann kombiniert werden für Schlafunterstützung.', '0', 'Niedrig', 'Anekdotisch; Physiologie'),
  ('gaba', 'baldrian', 'positiv', 'mittel', 'bidirektional', '✅ Beide GABAerg: Baldrian enthält GABA und moduliert GABA-A-Rezeptoren.', '⚠️ Möglicherweise additive sedierende Effekte.', '⚠️ Vorsicht bei Kombination; verstärkte Sedierung möglich.', '0', 'Niedrig', 'Traditionell; begrenzte Studien'),
  ('gaba', '5-htp', 'neutral', 'schwach', 'bidirektional', '⚠️ Unterschiedliche Neurotransmitter-Systeme: GABA (inhibitorisch) vs. 5-HTP (Serotonin-Vorstufe).', '⚠️ GABA selbst verursacht KEIN Serotonin-Syndrom; aber Vorsicht bei gleichzeitiger SSRI-Therapie.', '⚠️ Kombination möglich, aber bei SSRIs/MAOIs ärztliche Rücksprache.', '0', 'Niedrig', 'Theoretisch'),
  ('gaba', 'passionsblume', 'positiv', 'mittel', 'bidirektional', '✅ Passionsblume moduliert GABA-A-Rezeptoren (Chrysin-Flavonoid).', '⚠️ Möglicherweise additive GABAerge Effekte.', '⚠️ Vorsicht bei Kombination; verstärkte Sedierung möglich.', '0', 'Niedrig', 'PMC3025277'),
  ('dha', 'vitamin-e', 'positiv', 'mittel', 'bidirektional', 'Vitamin E schützt DHA (6 Doppelbindungen!) vor Oxidation', 'Verlängerte Stabilität, weniger Lipidperoxidation', 'Kombination empfohlen', '-', 'Hoch', 'GOED'),
  ('dha', 'arachidonsaeure', 'positiv', 'stark', 'bidirektional', 'ARA (Arachidonsäure) und DHA werden beide im Gehirn akkumuliert. Kinderärzte empfehlen ARA:DHA ≥1:1 in Säuglingsnahrung.', 'Balancierte Entwicklung von Gehirn und Immunsystem', '⭐ In Säuglingsnahrung: ARA ≥ DHA empfohlen (obwohl EU nicht vorgeschrieben!)', '-', 'Hoch', 'ESPGHAN; Europäische Kinderärzte'),
  ('dha', 'epa', 'neutral', 'mittel', 'bidirektional', 'DHA: Gehirn/Sehkraft (strukturell). EPA: Anti-inflammatorisch, kardiovaskulär (REDUCE-IT). ⚠️ DHA erhöht LDL (+7%), EPA nicht!', 'Unterschiedliche Wirkprofile - Anwendung anpassen!', 'Gehirn/Sehkraft: DHA-dominant. Kardiovaskulär: EPA-dominant. Depression: NUR EPA!', '-', 'Hoch', 'ComparED; REDUCE-IT vs. STRENGTH'),
  ('dha', 'phospholipide', 'positiv', 'mittel', 'A→B', 'DHA als Phospholipid (Krillöl, Algenöl) zeigt verbesserte Aufnahme ins Gehirn (MFSD2A-Transporter bevorzugt LPC-DHA).', 'Verbesserte ZNS-Penetration', 'Für Gehirn-Anwendung: DHA-Phospholipid-Form bevorzugen', '-', 'Mittel', 'MFSD2A-Forschung'),
  ('dha', 'algenoel-dha', 'neutral', 'schwach', 'bidirektional', 'Algen-DHA (Schizochytrium) zeigt gleichwertige Bioverfügbarkeit wie Fisch-DHA (RCT 2024: +212% vs. +161%).', 'Vegane Alternative ohne Qualitätseinbußen', 'Algen-DHA = Fisch-DHA. Für Veganer: Schizochytrium oder C. cohnii.', '-', 'Hoch', 'PMC12524788; MDPI 2024'),
  ('dha', 'curcumin', 'positiv', 'schwach', 'bidirektional', 'Theoretisch synergistische neuroprotektive Effekte. Beide erhöhen BDNF.', 'Potenzielle synergistische Neuroprotektion', 'Kombination in kognitiven Formeln sinnvoll', '-', 'Niedrig', 'Präklinische Daten'),
  ('kokosoel', 'mct-oel-c8-c10', 'neutral', 'stark', 'MCT >> Kokosöl', '⚠️ WICHTIGER UNTERSCHIED: Kokosöl enthält nur 13-15% echte MCT (C8+C10)! MCT-Öl enthält 95-100%. Für Ketose ist MCT-Öl 6-8x effektiver als Kokosöl.', 'Kokosöl ist KEIN Ersatz für MCT-Öl bei Ketose.', 'Für Ketose: MCT-Öl verwenden. Kokosöl nur für Kochen/Kosmetik.', '-', 'Hoch', 'St-Pierre 2019, Frontiers Nutrition 2020'),
  ('kokosoel', 'laurinsaeure-c12', 'positiv', 'stark', 'Kokosöl → C12', 'Kokosöl ist die HAUPTQUELLE für Laurinsäure (45-53%). Die antimikrobielle Wirkung von Kokosöl kommt primär aus der Laurinsäure (→ Monolaurin).', 'Antimikrobielle Wirkung von Kokosöl = Laurinsäure-Wirkung.', 'Für antimikrobielle Anwendung: Monolaurin-Supplements sind konzentrierter.', '-', 'Hoch', 'Kabara 1972'),
  ('kokosoel', 'olivenoel', 'neutral', 'stark', 'Olivenöl > Kokosöl', 'AHA-Empfehlung: Olivenöl (ungesättigt) ist herzgesünder als Kokosöl (gesättigt). Kokosöl erhöht LDL (+10,5 mg/dL), Olivenöl senkt LDL.', 'Für Herzgesundheit: Olivenöl bevorzugen!', 'Kokosöl nur für spezielle Anwendungen (Backen, Kosmetik), Olivenöl für täglichen Gebrauch.', '-', 'Hoch', 'AHA 2017, Neelakantan 2020'),
  ('kokosoel', 'omega-3-fettsaeuren', 'positiv', 'mittel', 'bidirektional', 'Omega-3 kann die LDL-erhöhende Wirkung von Kokosöl teilweise ausgleichen durch Senkung der Triglyceride.', 'Bei Kokosölkonsum: Omega-3-Balance beachten.', 'Ergänzung mit Omega-3 bei regelmäßigem Kokosölkonsum erwägen.', '-', 'Mittel', 'Allgemeine Ernährungsempfehlungen'),
  ('palmkernoel', 'kokosoel', 'neutral', 'mittel', 'Kokosöl > Palmkernöl', 'Ähnliches Fettsäureprofil, aber: Palmkernöl hat WENIGER echte MCT (~7% vs. 13%) und MASSIVE Umweltprobleme.', 'Kokosöl ist in jeder Hinsicht vorzuziehen.', 'Palmkernöl NICHT empfehlen - Kokosöl oder MCT-Öl wählen.', '-', 'Mittel', 'Fettsäureanalysen, Umweltberichte'),
  ('whey-protein-konzentrat', 'kreatin-monohydrat', 'positiv', 'mittel', 'bidirektional', '✅ Komplementäre Mechanismen: Whey (Aminosäuren/MPS) + Kreatin (ATP-Regeneration/Zellvolumisierung).', '✅ Burke 2001 (PMID 11591884): Größere FFM-Zunahme und Kraftsteigerung bei Kombination vs. Whey allein.', '✅ EMPFOHLENE Kombination für Muskelaufbau und Kraft.', '0', 'Mittel', 'PMID 11591884'),
  ('whey-protein-konzentrat', 'beta-alanin', 'positiv', 'schwach', 'bidirektional', '✅ Unterschiedliche Mechanismen: Whey (Protein) + Beta-Alanin (Carnosin/Puffer).', '⚠️ Keine direkten Interaktionsstudien; theoretisch komplementär.', '✅ Können kombiniert werden.', '0', 'Niedrig', 'Theoretisch'),
  ('whey-protein-konzentrat', 'vitamin-d', 'positiv', 'mittel', 'bidirektional', '✅ Vitamin D verstärkt Protein-Effekte auf Muskelmasse bei Älteren.', '✅ PMID 37196876: Signifikant bessere Ergebnisse bei kombinierter Supplementierung.', '✅ EMPFOHLEN bei Älteren für Sarkopenie-Prävention.', '0', 'Mittel', 'PMID 37196876'),
  ('whey-protein-konzentrat', 'casein', 'positiv', 'schwach', 'bidirektional', '✅ Whey = schnelle Absorption (Peak ~1h); Casein = langsame Absorption (bis 7h).', '⚠️ Kombination möglicherweise verlängerte Aminosäure-Verfügbarkeit; nicht eindeutig überlegen.', '✅ Casein vor dem Schlaf; Whey tagsüber = sinnvolle Strategie.', '0', 'Niedrig', 'Physiologie')
INSERT INTO wechselwirkungen_supplements (supplement_a, supplement_b, typ, staerke, richtung, mechanismus, praktische_auswirkung, empfehlung, zeitabstand_h, evidenz, quelle) VALUES
  ('whey-protein-konzentrat', 'kohlenhydrate', 'neutral', 'schwach', 'bidirektional', '⚠️ "Insulin-Spike-Theorie" wissenschaftlich NICHT bestätigt für MPS.', '⚠️ Protein allein erhöht Insulin ausreichend; KH bieten KEINEN zusätzlichen MPS-Nutzen (PMID 23360586).', '⚠️ KH nur nötig für Glykogen-Resynthese (Ausdauer, mehrfaches Training/Tag).', '0', 'Niedrig', 'PMID 23360586'),
  ('whey-protein-konzentrat', 'hmb', 'positiv', 'schwach', 'bidirektional', '✅ Unterschiedliche Mechanismen: Whey (MPS) + HMB (Anti-Katabolismus).', '⚠️ HMB primär bei Untrainierten/Älteren wirksam; bei Trainierten limitierter Zusatznutzen.', '⚠️ Für Ältere/Untrainierte: Kombination möglicherweise sinnvoll.', '0', 'Niedrig', 'Theoretisch'),
  ('whey-protein-isolat', 'kreatin-monohydrat', 'positiv', 'mittel', 'bidirektional', '✅ Komplementäre Mechanismen: WPI (Aminosäuren/MPS) + Kreatin (ATP-Regeneration).', '✅ Verschiedene Wirkmechanismen; keine Interaktion.', '✅ Können kombiniert werden.', '0', 'Mittel', 'Physiologie'),
